# ---------- FIGURE 4: self-transition curve P(letter -> same letter), 4 sets overlaid ----------
x = np.arange(20)
plt.figure(figsize=(9, 5))
for k in ["synthetic", "AA", "SS", "3Di"]:
    plt.plot(x, SELF_TRANS[k], color=COL[k], lw=2.0, marker="o", ms=4, label=k)
plt.axhline(1/20, ls=":", lw=1, color="0.5")
plt.text(19.2, 1/20, "random (1/20)", fontsize=8, color="0.5", va="center")
plt.xticks(x, LETTERS); plt.xlabel("letter"); plt.ylabel("P(letter is followed by itself)")
plt.title("Self-transition probability — four sets  (SS letters repeat ~86% of the time)")
plt.legend(); plt.tight_layout(); plt.savefig("four_sets_self_transition.png", dpi=150, bbox_inches="tight"); plt.show()

# ---------- FIGURE 5: full transition-probability heatmaps, shared 20-letter axis ----------
fig, axes = plt.subplots(1, 4, figsize=(16, 4.4), constrained_layout=True)
for ax, k in zip(axes, ["synthetic", "AA", "SS", "3Di"]):
    im = ax.imshow(np.array(TRANS[k]), vmin=0, vmax=1, cmap="magma", aspect="equal")
    ax.set_title(k); ax.set_xticks(x); ax.set_yticks(x)
    ax.set_xticklabels(LETTERS, fontsize=6); ax.set_yticklabels(LETTERS, fontsize=6)
    ax.set_xlabel("next letter"); ax.set_ylabel("current letter")
fig.colorbar(im, ax=axes, shrink=0.8, label="P(next | current)")
fig.suptitle("Transition probability P(next | current) — SS collapses onto its 3-letter diagonal")
plt.savefig("four_sets_transition_heatmaps.png", dpi=150, bbox_inches="tight"); plt.show()
